Visualisation géolocalisée des indicateurs clés (Données les plus récentes).
#| echo: false #| warning: false
import folium from health4earth.data_ingest import load_merged_data
df = load_merged_data() # On prend 2019 car c’est l’année la plus complète pour la pollution df_recent = df[df[‘year’] == 2019]

Liste des pays à afficher
capitals = { ‘France’: [48.85, 2.35], ‘United States’: [38.90, -77.03], ‘China’: [39.90, 116.40], ‘India’: [28.61, 77.20], ‘Brazil’: [-15.78, -47.92], ‘Germany’: [52.52, 13.40] }
m = folium.Map(location=[25, 0], zoom_start=2, tiles=“CartoDB positron”)
for country, coords in capitals.items(): row = df_recent[df_recent[‘country’] == country]
if not row.empty:
    co2 = row['co2'].values[0]
    life = row['life_expectancy'].values[0]
    deaths = int(row['pollution_deaths'].values[0])

    # Code HTML pour le popup interactif
    html = f"""
    &lt;div style="font-family:sans-serif; width:180px"&gt;
        &lt;h4&gt;{country}&lt;/h4&gt;
        &lt;hr&gt;
        &lt;b&gt;CO2:&lt;/b&gt; {co2:.0f} Mt&lt;br&gt;
        &lt;b&gt;Vie:&lt;/b&gt; {life:.1f} ans&lt;br&gt;
        &lt;b&gt;Décès (Air):&lt;/b&gt; {deaths:,}&lt;br&gt;
        &lt;br&gt;
        &lt;a href="index.html" target="_top" style="color:blue"&gt;Voir Analyse 📈&lt;/a&gt;
    &lt;/div&gt;
    """

    # Couleur selon le CO2
    color = 'red' if co2 &gt; 1000 else 'orange' if co2 &gt; 300 else 'green'

    folium.Marker(
        location=coords,
        popup=folium.Popup(html, max_width=250),
        icon=folium.Icon(color=color, icon="info-sign")
    ).add_to(m)
m
